// Worked focus: httpsts-transport-domain-response-owner — Separate transport parsing, domain decisions, persistence, external effects, and serialization while assigning exactly one response owner.
// Evidence: httpsts-worked-http-server-ts-middleware-errors-architecture-3
// Competency: httpsts-worked-http-server-ts-middleware-errors-architecture-3.
// Case 5798: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_middleware_errors_architecture_3(trusted: boolean, parsed: boolean, authorized: boolean, headersSent: boolean): { stage: string; status: number; delegate: boolean } {
  if (headersSent) return { stage: "error-delegate", status: 500, delegate: true };
  if (!trusted) return { stage: "trust", status: 400, delegate: false };
  if (!parsed) return { stage: "parse", status: 422, delegate: false };
  if (!authorized) return { stage: "authorize", status: 403, delegate: false };
  return { stage: "handler", status: 204, delegate: false };
}

